module top_module(input wire [3:0] in, input wire [1:0] s, output wire out);reg [3:0] invalid_out;
    always @(in or s)
        case (s)
            2'b00: invalid_out = in[0];
            2'b01: invalid_out = in[1];
            2'b10: invalid_out = in[2];
            2'b11: invalid_out = in[3];
            default: invalid_out = 4'b0;
        endcase
    assign out = invalid_out;
endmodule
